#include <iostream>

int main()
{
    int R{};
    int C{};
    std::cin >> R >> C;

    // Read an R x C dynamic matrix, build its C x R transpose in a second
    // dynamic matrix, print the transpose, then free both.

    return 0;
}

solution_code:
#include <iostream>

int main()
{
    int R{};
    int C{};
    std::cin >> R >> C;

    int** original{ new int*[R] };
    for (int r{ 0 }; r < R; ++r)
        original[r] = new int[C]{};

    for (int r{ 0 }; r < R; ++r)
        for (int c{ 0 }; c < C; ++c)
            std::cin >> original[r][c];

    int** transposed{ new int*[C] };
    for (int c{ 0 }; c < C; ++c)
        transposed[c] = new int[R]{};

    for (int r{ 0 }; r < R; ++r)
        for (int c{ 0 }; c < C; ++c)
            transposed[c][r] = original[r][c];

    for (int c{ 0 }; c < C; ++c)
    {
        for (int r{ 0 }; r < R; ++r)
        {
            if (r > 0)
                std::cout << ' ';
            std::cout << transposed[c][r];
        }
        std::cout << '\n';
    }

    for (int r{ 0 }; r < R; ++r)
        delete[] original[r];
    delete[] original;

    for (int c{ 0 }; c < C; ++c)
        delete[] transposed[c];
    delete[] transposed;

    return 0;
}
